	('a1a0b978-ec40-4c2a-b1da-6717997fb75f', '06532477-fa45-49af-8d02-cd247eba5d7e', 'ตัวแทนขายประกัน', 'ตัวแทนขายประกัน-mmbt21ly-41', 'รับสมัครตัวแทนขายประกันชีวิตและประกันภัย ดูแลลูกค้าทั้งรายเก่าและรายใหม่ นำเสนอแผนประกันที่เหมาะสมกับความต้องการของลูกค้าแต่ละราย สร้างฐานลูกค้าของตัวเอง มีรายได้จากค่าคอมมิชชั่น', 'อายุ 20 ปีขึ้นไป มีใจรักงานขาย มีทักษะการสื่อสารที่ดี สามารถทำงานภายใต้แรงกดดันได้', '["วันหยุดพักร้อน", "ทำงานจากบ้านได้", "ค่าเดินทาง", "ประกันสังคม", "เบี้ยขยัน"]', 20000.00, 50000.00, 1, 'CONTRACT', 'ONSITE', 'ภูเก็ต', 'ลาดกระบัง', '["การขายประกัน", "การสร้างความสัมพันธ์กับลูกค้า", "การเจรจาต่อรอง"]', 'ACTIVE', '2026-03-04 08:59:13.702', '2026-06-02 08:59:13.702', '2026-03-04 08:59:13.810', 1, '17:00', NULL, 3, '09:00', 0, 0, '5 วัน/สัปดาห์', 'ต่ำกว่ามัธยมศึกษา', 'งานขาย', 'ขายสินค้าและบริการ', NULL, 'HR Department', '074-984-7672', 36, 18, 2, 'ชาย', '["BTS", "รถประจำทาง"]', '522 ถนนสาทร แขวงลาดกระบัง เขตลาดกระบัง ภูเก็ต', 0, NULL),
	('a1a331b3-3e7a-4695-89a9-7ba28d18dd0d', '06532477-fa45-49af-8d02-cd247eba5d7e', 'VDO Editor Video Editing', 'vdo-editor-video-editing-mmbv4uhn', '<p><span style="color: rgb(46, 56, 73);">ตำแหน่ง: VDO Editor / Video Editingบริษัท ULTIMATE INNOTECH CO., LTD. กำลังมองหาตำแหน่ง VDO Editor / Video Editing ที่มีความเชี่ยวชาญ เพื่อร่วมงานในทีมผลิตเนื้อหาภาพยนตร์ วิดีโอ และสื่อโฆษณาของเรา ในพื้นที่กรุงเทพมหานครหน้าที่หลัก</span><br></p><ul><li><p>ตัดต่อและตกแต่งวิดีโอตามแนวคิดและรูปแบบที่กำหนด</p></li><li><p>ดำเนินการจัดการ และจัดหาภาพ เสียง และองค์ประกอบอื่น ๆ สำหรับการตัดต่อวิดีโอ</p></li><li><p>ร่วมมือกับทีมงานอื่น ๆ เช่น ผู้กำกับ ช่างภาพ และนักเขียนบทเพื่อสร้างผลงานที่มีประสิทธิภาพ</p></li><li><p>ปรับแต่งและแก้ไขวิดีโอให้สอดคล้องกับวัตถุประสงค์การใช้งาน เช่น โฆษณา การนำเสนอ หรือสื่อทางการตลาด</p></li><li><p>ติดตามและปรับปรุงเทคนิคการตัดต่อวิดีโอให้ทันสมัยอยู่เสมอ<br></p></li></ul><p></p>', '<ul><li><p>มีประสบการณ์ด้านการตัดต่อวิดีโอและการใช้ซอฟต์แวร์ตัดต่อ เช่น Adobe Premiere Pro, Final Cut Pro, Avid Media Composer อย่างน้อย 3 ปี</p></li><li><p>มีทักษะการตัดต่อวิดีโอที่ดี สามารถสร้างสรรค์งานที่มีความคิดสร้างสรรค์และแปลกใหม่</p></li><li><p>มีความเข้าใจและความสนใจในอุตสาหกรรมโฆษณา สื่อ และวิดีโอ</p></li><li><p>มีความรู้เกี่ยวกับการใช้เครื่องมือ ซอฟต์แวร์ และเทคโนโลยีต่าง ๆ ที่เกี่ยวข้องกับการตัดต่อวิดีโอ</p></li><li><p>มีความสามารถในการทำงานเป็นทีม มีมนุษยสัมพันธ์ที่ดี และสื่อสารได้อย่างมีประสิทธิภาพ</p></li></ul><p></p>', '["ค่าล่วงเวลา", "ที่พัก", "ชุดพนักงาน", "อาหาร", "โบนัส", "ประกันสังคม", "ค่าคอมมิชชัน", "ค่าเดินทาง"]', 20000.00, 50000.00, 1, 'FULL_TIME', 'ONSITE', NULL, NULL, '["Premiere pro", "Capcut", "Vegas Pro", "AfterEffect", "DaVinci Resolve", "Photoshop"]', 'ACTIVE', '2026-03-07 18:03:36.512', NULL, '2026-03-04 09:57:23.679', 1, NULL, '<iframe src="https://www.google.com/maps/embed?pb=!1m17!1m12!1m3!1d1882.7709764658293!2d100.49335480558484!3d13.725679884238055!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m2!1m1!2zMTPCsDQzJzM0LjUiTiAxMDDCsDI5JzM1LjEiRQ!5e0!3m